const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const item = $input.item.json;
const cmd = `npx playwright test "${item.testPath}" --reporter=json`;
const cwd = 'c:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow';
const startTime = new Date();
let stdout = '', stderr = '', exitCode = 0;
try {
  stdout = execSync(cmd, { cwd, stdio: 'pipe' }).toString();
} catch (e) {
  exitCode = e.status || 1;
  stdout = (e.stdout || '').toString();
  stderr = (e.stderr || e.message || '').toString();
}
const duration = ((new Date() - startTime) / 1000).toFixed(2);
let binaryData = null, stats = { total: 0, passed: 0, failed: 0 }, testCases = [];
try {
  const jsonMatch = stdout.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const jsonData = JSON.parse(jsonMatch[0]);
    if (jsonData.stats) {
        stats.passed = jsonData.stats.expected || 0;
        stats.failed = jsonData.stats.unexpected || 0;
        stats.total = stats.passed + stats.failed + (jsonData.stats.skipped || 0);
    }
    jsonData.suites?.forEach(s => s.specs?.forEach(sp => sp.tests?.forEach(t => {
        const res = t.results?.[0];
        testCases.push({ title: sp.title, status: res ? res.status : 'failed' });
        const att = res?.attachments?.find(a => a.name === 'screenshot');
        if (att && att.path && !binaryData) {
            const src = att.path.includes(':') ? att.path : path.join(cwd, att.path);
            if (fs.existsSync(src)) binaryData = fs.readFileSync(src).toString('base64');
        }
    })));
  }
} catch (e) {}
const cleanLogs = (stdout + '\n' + stderr).trim().replace(/[\u001b\u009b][[\]()#;?]*(?:(?:(?:[a-zA-Z\\d]*(?:;[-a-zA-Z\\d\/#&.:=?%@~_]*)*)?\u0007)|(?:(?:\d{1,4}(?:;\d{0,4})*)?[\dA-PR-TZcf-ntqry=><~]))/g, '');
let finalStatus = exitCode === 0 && (stats.total > 0 && stats.failed === 0) ? 'passed' : 'failed';
if (stats.total === 0) finalStatus = 'failed';
const reportSummary = testCases.map(tc => `${tc.status === 'passed' ? '✅' : '❌'} ${tc.title}`).join('\n');
const result = { json: { ...item, status: finalStatus, duration: `${duration}s`, stats, reportSummary, errorLogs: cleanLogs.substring(0, 3500), hasScreenshot: !!binaryData } };
if (binaryData) result.binary = { screenshot: { data: binaryData, mimeType: 'image/png', fileName: 'screenshot.png' } };
return result;

